import{_ as e}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as o,o as i,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Cloudflare API Token 設定","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Safety/cloudflare-api-token.md","filePath":"zh-TW/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"zh-TW/Safety/cloudflare-api-token.md"};function p(n,a,h,s,u,c){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="cloudflare-api-token-設定" tabindex="-1">Cloudflare API Token 設定 <a class="header-anchor" href="#cloudflare-api-token-設定" aria-label="Permalink to &quot;Cloudflare API Token 設定&quot;">​</a></h1><p>Cloudflare API Token 用來讓系統在檔案異動後，主動清除 Cloudflare CDN 快取。</p><p><img src="'+e+'" alt="Cloudflare API Token 設定" loading="lazy"></p><h2 id="功能入口" tabindex="-1">功能入口 <a class="header-anchor" href="#功能入口" aria-label="Permalink to &quot;功能入口&quot;">​</a></h2><p>進入後台後打開：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 安全設定 -&gt; Cloudflare API Token</span></span></code></pre></div><p>頁面需要填三項：</p><ul><li>Zone ID</li><li>帳號信箱</li><li>API Key</li></ul><h2 id="這個設定有什麼用" tabindex="-1">這個設定有什麼用 <a class="header-anchor" href="#這個設定有什麼用" aria-label="Permalink to &quot;這個設定有什麼用&quot;">​</a></h2><p>Cloudflare 會快取公開圖片。</p><p>快取可以讓圖片開得更快，但也會造成一個問題：當你刪除、封鎖、取代或移動圖片後，外部訪客可能仍會在一段時間內看到舊內容。</p><p>設定 Cloudflare API Token 後，系統會在相關操作完成時，請 Cloudflare 清除對應快取。</p><p>適合這些情境：</p><ul><li>刪除圖片後，希望公開連結盡快失效。</li><li>封鎖圖片後，希望外部訪客盡快看不到原圖。</li><li>覆蓋同名圖片後，希望使用者盡快看到新圖。</li><li>移動或重新命名檔案後，希望舊路徑快取盡快更新。</li><li>調整公開存取規則後，希望公開圖庫和隨機圖快取盡快刷新。</li></ul><h2 id="不設定會怎樣" tabindex="-1">不設定會怎樣 <a class="header-anchor" href="#不設定會怎樣" aria-label="Permalink to &quot;不設定會怎樣&quot;">​</a></h2><p>不設定也可以正常使用 ImgBed。</p><p>只是系統不會主動清 Cloudflare CDN 快取，外部使用者可能在快取自然過期前繼續看到舊內容。</p><h2 id="zone-id-怎麼填" tabindex="-1">Zone ID 怎麼填 <a class="header-anchor" href="#zone-id-怎麼填" aria-label="Permalink to &quot;Zone ID 怎麼填&quot;">​</a></h2><p>Zone ID 是 Cloudflare 裡目前站點的 Zone ID。</p><p>取得方式：</p><ol><li>登入 Cloudflare Dashboard。</li><li>進入 ImgBed 網域所在的站點。</li><li>在站點 Overview 頁找到 Zone ID。</li><li>複製後填入 <code>Zone ID</code>。</li></ol><p>注意：這裡填的是站點 Zone ID，不是 Account ID。</p><h2 id="帳號信箱怎麼填" tabindex="-1">帳號信箱怎麼填 <a class="header-anchor" href="#帳號信箱怎麼填" aria-label="Permalink to &quot;帳號信箱怎麼填&quot;">​</a></h2><p>填 Cloudflare 登入信箱。</p><p>這個信箱需要和下面的 API Key 搭配使用。</p><h2 id="api-key-怎麼填" tabindex="-1">API Key 怎麼填 <a class="header-anchor" href="#api-key-怎麼填" aria-label="Permalink to &quot;API Key 怎麼填&quot;">​</a></h2><p>這裡填 Cloudflare 的 Global API Key。</p><p>取得方式：</p><ol><li>登入 Cloudflare Dashboard。</li><li>進入個人資料。</li><li>打開 API Tokens 頁面。</li><li>找到 Global API Key。</li><li>檢視並複製。</li><li>貼到後台的 API Key 欄位。</li></ol><p><img src="'+l+'" alt="查看全域金鑰" loading="lazy"></p><h2 id="儲存後什麼時候生效" tabindex="-1">儲存後什麼時候生效 <a class="header-anchor" href="#儲存後什麼時候生效" aria-label="Permalink to &quot;儲存後什麼時候生效&quot;">​</a></h2><p>填寫完成後按儲存。</p><p>儲存成功後，後續檔案異動會自動嘗試清除 Cloudflare 快取。</p><p>已經發生過的舊操作不會自動補清。如果你之前刪除或取代過檔案，但當時尚未設定這些資訊，可能需要等 Cloudflare 快取自然過期，或到 Cloudflare 後台手動清除快取。</p><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="一定要設定嗎" tabindex="-1">一定要設定嗎？ <a class="header-anchor" href="#一定要設定嗎" aria-label="Permalink to &quot;一定要設定嗎？&quot;">​</a></h3><p>不是必填。</p><p>如果你的網域沒有接 Cloudflare，或不介意 CDN 快取延遲，可以不填。</p><h3 id="填錯會影響上傳嗎" tabindex="-1">填錯會影響上傳嗎？ <a class="header-anchor" href="#填錯會影響上傳嗎" aria-label="Permalink to &quot;填錯會影響上傳嗎？&quot;">​</a></h3><p>通常不會影響正常上傳和存取。</p><p>填錯時，系統只是無法成功請 Cloudflare 清快取，舊快取可能會繼續存在一段時間。</p><h3 id="為什麼刪除圖片後外面還能打開" tabindex="-1">為什麼刪除圖片後外面還能打開？ <a class="header-anchor" href="#為什麼刪除圖片後外面還能打開" aria-label="Permalink to &quot;為什麼刪除圖片後外面還能打開？&quot;">​</a></h3><p>最常見原因是 Cloudflare CDN 還快取著舊檔案。</p><p>設定正確後，系統會在刪除時主動清除對應 URL 快取。</p><h3 id="為什麼替換同名圖片後還是舊圖" tabindex="-1">為什麼替換同名圖片後還是舊圖？ <a class="header-anchor" href="#為什麼替換同名圖片後還是舊圖" aria-label="Permalink to &quot;為什麼替換同名圖片後還是舊圖？&quot;">​</a></h3><p>這也是 CDN 快取常見現象。</p><p>設定後，系統會在覆蓋同名檔案時嘗試清掉舊 URL 快取，讓新圖更快生效。</p>',47)])])}const P=o(d,[["render",p]]);export{m as __pageData,P as default};
